/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering based on notification type
 * - Recipient email validation
 * - Pluggable transport for testability (inject real provider or mock)
 *
 * Implements: NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents a rendered email ready for transport.
 */
export interface EmailMessage {
  from: string;
  to: string;
  replyTo?: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport interface — abstracts the actual email sending mechanism.
 * Implement this with SendGrid, SES, SMTP, or a test double.
 */
export interface EmailTransport {
  sendMail(message: EmailMessage): Promise<{ messageId: string }>;
}

export interface EmailConfig {
  /** Sender email address */
  from: string;
  /** Reply-to address */
  replyTo?: string;
  /** Email transport implementation */
  transport: EmailTransport;
}

/**
 * Email templates keyed by notification type.
 * Each template receives the payload and returns { html, text }.
 */
type TemplateRenderer = (payload: NotificationPayload) => { html: string; text: string };

const EMAIL_TEMPLATES: Record<NotificationType, TemplateRenderer> = {
  'order-confirmation': (payload) => ({
    html: `<h1>Order Confirmed</h1><p>${escapeHtml(payload.body)}</p><p>Thank you for your order!</p>`,
    text: `Order Confirmed\n\n${payload.body}\n\nThank you for your order!`,
  }),
  'order-status-update': (payload) => ({
    html: `<h1>Order Update</h1><p>${escapeHtml(payload.body)}</p>`,
    text: `Order Update\n\n${payload.body}`,
  }),
  'welcome': (payload) => ({
    html: `<h1>Welcome!</h1><p>${escapeHtml(payload.body)}</p><p>We're glad to have you.</p>`,
    text: `Welcome!\n\n${payload.body}\n\nWe're glad to have you.`,
  }),
  'account-updated': (payload) => ({
    html: `<h1>Account Updated</h1><p>${escapeHtml(payload.body)}</p>`,
    text: `Account Updated\n\n${payload.body}`,
  }),
};

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function isValidEmail(email: string): boolean {
  return EMAIL_REGEX.test(email);
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');

  constructor(private config: EmailConfig) {}

  /**
   * Resolve and validate the recipient email address.
   * Returns the validated email or throws if invalid.
   */
  private resolveRecipient(recipient: string): string {
    const email = recipient.trim().toLowerCase();
    if (!isValidEmail(email)) {
      throw new Error(`Invalid email recipient: ${recipient}`);
    }
    return email;
  }

  /**
   * Render an email from a notification payload using the appropriate template.
   */
  renderEmail(payload: NotificationPayload): EmailMessage {
    const to = this.resolveRecipient(payload.recipient);
    const template = EMAIL_TEMPLATES[payload.type];
    const { html, text } = template(payload);

    return {
      from: this.config.from,
      to,
      replyTo: this.config.replyTo,
      subject: payload.subject,
      html,
      text,
    };
  }

  /**
   * Send an email notification.
   * Validates recipient, renders template, and delivers via transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const message = this.renderEmail(payload);

      this.logger.info(`Sending email to ${message.to}: "${message.subject}"`);

      const result = await this.config.transport.sendMail(message);

      this.logger.info(`Email sent successfully: ${result.messageId}`);

      return {
        success: true,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
        error: errorMessage,
      };
    }
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { EmailConfig, EmailTransport, EmailMessage } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function createMockTransport() {
  return {
    sendMail: vi.fn<(message: EmailMessage) => Promise<{ messageId: string }>>().mockResolvedValue({
      messageId: 'msg-001',
    }),
  };
}

function createPayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date(),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let transport: ReturnType<typeof createMockTransport>;
  let config: EmailConfig;
  let adapter: EmailAdapter;

  beforeEach(() => {
    transport = createMockTransport();
    config = { from: 'noreply@taskflow.com', replyTo: 'support@taskflow.com', transport };
    adapter = new EmailAdapter(config);
  });

  describe('channel', () => {
    it('should report email as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('renderEmail', () => {
    it('should render order-confirmation template', () => {
      const payload = createPayload();
      const email = adapter.renderEmail(payload);

      expect(email.from).toBe('noreply@taskflow.com');
      expect(email.to).toBe('alice@example.com');
      expect(email.replyTo).toBe('support@taskflow.com');
      expect(email.subject).toBe('Order Confirmation: order-1');
      expect(email.html).toContain('Order Confirmed');
      expect(email.html).toContain('Widget x2');
      expect(email.text).toContain('Order Confirmed');
      expect(email.text).toContain('Thank you for your order!');
    });

    it('should render order-status-update template', () => {
      const payload = createPayload({
        type: 'order-status-update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('Order Update');
      expect(email.text).toContain('pending to confirmed');
    });

    it('should render welcome template', () => {
      const payload = createPayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow!',
        body: 'Welcome aboard, Alice!',
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('Welcome!');
      expect(email.html).toContain("We're glad to have you.");
      expect(email.text).toContain('Welcome aboard, Alice!');
    });

    it('should render account-updated template', () => {
      const payload = createPayload({
        type: 'account-updated',
        subject: 'Account Updated',
        body: 'Your email has been changed.',
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('Account Updated');
      expect(email.text).toContain('Your email has been changed.');
    });

    it('should escape HTML in body content', () => {
      const payload = createPayload({
        body: '<script>alert("xss")</script>',
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).not.toContain('<script>');
      expect(email.html).toContain('&lt;script&gt;');
    });

    it('should normalize recipient email to lowercase', () => {
      const payload = createPayload({ recipient: 'Alice@Example.COM' });
      const email = adapter.renderEmail(payload);

      expect(email.to).toBe('alice@example.com');
    });

    it('should reject invalid email recipients', () => {
      const payload = createPayload({ recipient: 'not-an-email' });

      expect(() => adapter.renderEmail(payload)).toThrow('Invalid email recipient');
    });

    it('should reject empty email recipients', () => {
      const payload = createPayload({ recipient: '' });

      expect(() => adapter.renderEmail(payload)).toThrow('Invalid email recipient');
    });
  });

  describe('send', () => {
    it('should send email through transport and return success', async () => {
      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();

      expect(transport.sendMail).toHaveBeenCalledOnce();
      const sentMessage = transport.sendMail.mock.calls[0]![0];
      expect(sentMessage.to).toBe('alice@example.com');
      expect(sentMessage.from).toBe('noreply@taskflow.com');
      expect(sentMessage.subject).toBe('Order Confirmation: order-1');
    });

    it('should return failure when transport throws', async () => {
      transport.sendMail.mockRejectedValue(new Error('SMTP connection refused'));

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
    });

    it('should return failure for invalid recipient without calling transport', async () => {
      const payload = createPayload({ recipient: 'bad-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email recipient');
      expect(transport.sendMail).not.toHaveBeenCalled();
    });

    it('should work without replyTo config', async () => {
      const adapterNoReply = new EmailAdapter({
        from: 'noreply@taskflow.com',
        transport,
      });

      const payload = createPayload();
      const result = await adapterNoReply.send(payload);

      expect(result.success).toBe(true);
      const sentMessage = transport.sendMail.mock.calls[0]![0];
      expect(sentMessage.replyTo).toBeUndefined();
    });

    it('should include metadata passthrough if provided', async () => {
      const payload = createPayload({
        metadata: { orderId: 'order-1', trackingUrl: 'https://track.example.com/123' },
      });

      const result = await adapter.send(payload);
      expect(result.success).toBe(true);
    });
  });
});
